import{_ as r,c as o,o as n,ae as s}from"./chunks/framework.B7Y1jjX-.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notes/学习/学校竞赛、项目/智能车/申报/申报书.md","filePath":"notes/学习/学校竞赛、项目/智能车/申报/申报书.md"}'),l={name:"notes/学习/学校竞赛、项目/智能车/申报/申报书.md"};function a(i,t,g,e,_,d){return n(),o("div",null,[...t[0]||(t[0]=[s('<h3 id="v1的问题" tabindex="-1">v1的问题 <a class="header-anchor" href="#v1的问题" aria-label="Permalink to &quot;v1的问题&quot;">​</a></h3><ul><li>国家级</li><li>YOLOv8</li><li>分工</li><li>经费</li><li>学校提供条件</li><li>项目所属一级二级学科 一级<strong>计算机科学与技术</strong> 二级</li></ul><h3 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h3><ul><li>格式需要统一</li><li>项目研究背景少4000</li><li>硬件图片展示（向机械组要）</li><li>保证前后逻辑的一致性</li><li>参考文献部分（针于对项目研究背景）</li><li>分工、成员信息、指导教师</li></ul><h3 id="v5的问题" tabindex="-1">v5的问题 <a class="header-anchor" href="#v5的问题" aria-label="Permalink to &quot;v5的问题&quot;">​</a></h3><ul><li>所属重点领域</li><li>所属二级学科</li><li>联系电话</li><li>申报日期</li></ul><h3 id="智能车" tabindex="-1">智能车 <a class="header-anchor" href="#智能车" aria-label="Permalink to &quot;智能车&quot;">​</a></h3><p>、### 一、基本信息 - <strong>申请号</strong>：202410938457.0 - <strong>申请公布号</strong>：CN118494632A - <strong>申请公布日</strong>：2024.08.16 - <strong>申请人</strong>：中国矿业大学 - <strong>发明人</strong>：江柏、李治霖、郭士洋等 ### 二、智能车组成结构 |<strong>组件</strong>|<strong>构成与功能</strong>| |----|----| |<strong>车体</strong>|框架结构，内部集成核心部件，外侧安装麦克纳姆轮，前端设云台和机械臂| |<strong>机械臂</strong>|• 含摄像头（OpenMV4高清智能摄像头）、探头、伸缩杆、3个舵机（舵机A/B/C）及机械杆A/B<br>• 通过三自由度控制（舵机A/B/C+云台）实现多角度检测，探头可深入裂缝| |<strong>负压吸附管道</strong>|• 呈“人”字三口形，由电动导管风扇（PMMA材质）、吸盘、通风口组成<br>• 管道内表面光滑，气流顺畅，吸附力均匀稳定<br>• 红外测距模块实时监测距离，动态调节风扇功率以适应墙面起伏| |<strong>麦克纳姆轮</strong>|• 对称安装于车体四周，由电机（TB6600驱动模块驱动）控制<br>• 支持全方位移动，减小转弯半径，提升灵活性| |<strong>总控制系统</strong>|• 含STM32F407微型控制器和NRF24L01无线通信模块<br>• 主控各子系统（机械臂、吸附管道、移动模块等），传输检测数据至远程终端| |<strong>红外测距模块</strong>|安装于车体下方四周，监测底盘与墙面距离，反馈至总控制系统调节吸附力| |<strong>蓄电池</strong>|通过LM2596S稳压模块供电，为摄像头、控制系统、电机等供电| ### 三、核心技术优势 1. <strong>移动与吸附</strong> - <strong>麦克纳姆轮</strong>：实现360°全方位移动，避免大幅转弯不稳，提升复杂墙面适应性。 - <strong>负压吸附系统</strong>：“人”字形管道设计增加吸盘数量，结合红外测距动态调节风扇功率，确保凹凸墙面稳定吸附，避免脱落风险。 2. <strong>检测能力</strong> - <strong>高自由度机械臂</strong>：三自由度控制（云台+舵机）结合伸缩杆，摄像头可环视障碍，探头深入狭小结构（如裂缝），实现精细化检测。 - <strong>智能控制</strong>：STM32F407微控制器集成多模块协同控制，无线通信实时传输数据，支持远程操作与决策。 3. <strong>安全与能效</strong> - 电动导管风扇采用PMMA材质，抗冲击、轻量化、环保。 - 按需调节风扇功率，节省能源，适应多场景作业。 ### 四、应用场景与价值 - <strong>场景</strong>：建筑外墙（含垂直墙面、复杂曲面）的缺陷检测（如裂缝、结构隐患），替代高危人工高空作业。 - <strong>价值</strong>： - 降低60%高空作业事故风险（对比传统人工检测）。 - 提升检测效率与精度，减少20%因漏检导致的维修风险。 - 结构简单、操作便捷，具备推广价值。 ### 五、附图说明 - <strong>图1-4</strong>：智能车正、侧、俯视及底部结构，展示组件布局。 - <strong>图5</strong>：负压吸附管道细节（风扇、吸盘、通风口位置）。 - <strong>图6</strong>：机械臂结构（舵机与机械杆连接关系）。 - <strong>图7</strong>：电路系统示意图（控制器、驱动模块、供电链路）。</p>',8)])])}const u=r(l,[["render",a]]);export{c as __pageData,u as default};
